args.sparql:
SELECT ?prevClub ?shareholder WHERE {
  ?player wdt:P569 "1983-06-12T00:00:00Z"^^xsd:dateTime ;
          wdt:P570 ?club1 .
  ?club1 rdfs:label "Guangzhou Pharmaceutical"@en ;
          wdt:P580 ?startTime1 .
  ?player wdt:P570 ?club2 .
  ?club2 wdt:P582 ?endTime2 .
  FILTER (?endTime2 < ?startTime1)
  ?club2 wdt:P727 ?shareholder .
}

