SELECT ?prevClub ?shareholder WHERE {
  ?player wdt:P569 "1983-06-12"^^xsd:date ;
          wdt:P570 ?prevClub.
  ?prevClub wdt:P582 ?endDate.
  ?player wdt:P570 wd:Q7231369.
  wd:Q7231369 wdt:P580 ?startDate.
  FILTER (?endDate < ?startDate)
  ?prevClub wdt:P727 ?shareholder.
}

SELECT ?prevClub ?shareholder WHERE {
  ?player wdt:P569 "1983-06-12"^^xsd:date;
          p:P570 ?currentStmt.
  ?currentStmt ps:P570 wd:Q7231369;
          pq:P580 ?currStart.
  ?currentStmt ps:P570 ?currClub.
